import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'


class EvalStatus extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0
        };
    }




        componentDidMount() {


            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var backUrl = properties.backend + `evalstatus`

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                this.setState({results: response})
                this.setState({screen: 1})

              })
              .catch(err => {
                console.log(err);
              });

        }




          render() {


            var header = "Loading ..."


            if (this.state.screen === 1) {
              header = ""
              var content = []

              console.log(this.state.results.complete)
              console.log(this.state.results.error)
              console.log(this.state.results.incomplete)


                var incomplete = []
                incomplete.push(<tr><td style={{padding: "10px"}}>Issued</td><td style={{padding: "10px"}}>Recipient</td><td style={{padding: "10px"}}>Evaluation</td><td style={{padding: "10px"}}>Rotation</td></tr>)
                this.state.results.incomplete.map(rec => {
                        incomplete.push(<tr><td>{rec.date}</td><td>{rec.evaluator}</td><td>{rec.title}</td></tr>)
                    }
                )



              content.push(<Tabs>
                <TabList>
                    <Tab>Incomplete</Tab>
                    <Tab>Complete</Tab>
                    <Tab>Error</Tab>
                </TabList>
                <TabPanel><div >
                    <table>{incomplete}</table>
                    </div></TabPanel>
                <TabPanel><div ></div></TabPanel>
                <TabPanel><div ></div></TabPanel>
            </Tabs>)

            }



            return (
                <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default EvalStatus
